def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    from collections import defaultdict, deque

    # Collect all tasks
    all_tasks = set(deps.keys())
    for prereqs in deps.values():
        all_tasks.update(prereqs)

    # Build graph and in-degree
    in_degree = {t: 0 for t in all_tasks}
    graph = defaultdict(list)

    for task, prereqs in deps.items():
        for p in prereqs:
            graph[p].append(task)
            in_degree[task] += 1

    # Kahn's algorithm with level-by-level BFS
    queue = deque(sorted([t for t in all_tasks if in_degree[t] == 0]))
    result = []

    while queue:
        level = sorted(queue)
        result.append(level)
        next_queue = []
        for task in level:
            for neighbor in graph[task]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    next_queue.append(neighbor)
        queue = deque(sorted(next_queue))

    # Check for cycle
    total = sum(len(level) for level in result)
    if total != len(all_tasks):
        return []

    return result
```

