        if cmd == "get":
            key = int(parts[1])
            if capacity == 0 or key not in cache:
                result.append(-1)
            else:
                cache.move_to_end(key)
                result.append(cache[key])
        elif cmd == "put":
            key = int(parts[1])
            value = int(parts[2])
            if capacity == 0:
                continue
            if key in cache:
                cache.move_to_end(key)
            cache[key] = value
            if len(cache) > capacity:
                cache.popitem(last=False)

