def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    # Build reverse dependency graph: package -> packages that depend on it
    reverse_deps = {}
    for pkg, dep_list in deps.items():
        for dep in dep_list:
            if dep not in reverse_deps:
                reverse_deps[dep] = []
            reverse_deps[dep].append(pkg)

    # BFS/DFS from changed packages through reverse deps
    result = set()
    stack = list(changed)
    while stack:
        pkg = stack.pop()
        if pkg in result:
            continue
        result.add(pkg)
        if pkg in reverse_deps:
            for dependent in reverse_deps[pkg]:
                if dependent not in result:
                    stack.append(dependent)

    return sorted(result)
```

